section.para:
   Litestream service is managed by a dedicated user named litestream
   which needs permission to the database file. Here's an example config which gives
   required permissions to access 
   grafana database:

{ pkgs, ... }:
{
  users.users.litestream.extraGroups = [ "grafana" ];

  services.litestream = {
    enable = true;

    environmentFile = "/run/secrets/litestream";

    serviceConfig.ExecStartPre = "+" + pkgs.writeShellScript "grant-grafana-permissions" ''
      find /var/lib/grafana -type d -exec chmod -v 755 {} \;
      find /var/lib/grafana -type f -exec chmod -v 660 {} \;
    '';

    settings = {
      dbs = [
        {
          path = "/var/lib/grafana/data/grafana.db";
          replicas = [{
            url = "s3://mybkt.litestream.io/grafana";
          }];
        }
      ];
    };
  };
}
